class Solution:
    def maximizeTheProfit(self, n: int, offers: List[List[int]]) -> int:
        # Sort offers by end index
        offers.sort(key=lambda x: x[1])

        # dp[i] represents the maximum profit up to house i
        dp = [0] * (n + 1)

        # Iterate through each offer
        for start, end, gold in offers:
            # dp[end + 1] = max(dp[end + 1], dp[start] + gold)
            dp[end + 1] = max(dp[end + 1], dp[start] + gold)

        # The maximum profit is the maximum value in dp
        return max(dp)
